package com.nattechnologies.trastcms.plugins.store;
import jakarta.validation.Valid; import org.springframework.http.*; import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/api/public/store") class StorePublicController{private final StoreService s;StorePublicController(StoreService s){this.s=s;}@GetMapping("/products")StoreDtos.PageResponse<StoreDtos.ProductResponse>products(@RequestParam(required=false)String search,@RequestParam(defaultValue="0")int page,@RequestParam(defaultValue="24")int size){return s.catalog(search,page,size);}@GetMapping("/products/{slug}")StoreDtos.ProductResponse product(@PathVariable String slug){return s.publicProduct(slug);}}
@RestController @RequestMapping("/api/admin/store") class StoreAdminController{private final StoreService s;StoreAdminController(StoreService s){this.s=s;}@GetMapping("/dashboard")StoreDtos.Dashboard dashboard(){return s.dashboard();}@GetMapping("/products")StoreDtos.PageResponse<StoreDtos.ProductResponse>products(@RequestParam(required=false)String search,@RequestParam(defaultValue="0")int page,@RequestParam(defaultValue="25")int size){return s.adminProducts(search,page,size);}@PostMapping("/products")@ResponseStatus(HttpStatus.CREATED)StoreDtos.ProductResponse create(@Valid@RequestBody StoreDtos.ProductRequest r){return s.save(null,r);}@PutMapping("/products/{id}")StoreDtos.ProductResponse update(@PathVariable String id,@Valid@RequestBody StoreDtos.ProductRequest r){return s.save(id,r);}@DeleteMapping("/products/{id}")@ResponseStatus(HttpStatus.NO_CONTENT)void delete(@PathVariable String id){s.delete(id);}@PostMapping("/products/{id}/inventory")StoreDtos.ProductResponse inventory(@PathVariable String id,@Valid@RequestBody StoreDtos.InventoryAdjustmentRequest r){return s.adjust(id,r);}@GetMapping("/inventory/movements")StoreDtos.PageResponse<StoreDtos.InventoryMovementResponse> movements(@RequestParam(defaultValue="0")int page,@RequestParam(defaultValue="50")int size){return s.movements(page,size);}}
